UPDATE `experiences` SET `narrative` = 'La mia passione per la programmazione è nata a 15 anni, con i primi passi in C# e sviluppo web. Grazie a diversi progetti realizzati durante e fuori dal percorso scolastico, ho avuto modo di espandere le mie conoscenze verso pratiche di sviluppo e scelte di progettazione con mentalità aziendale' WHERE `id` = 'itt-diploma';
UPDATE `experiences` SET `narrative` = 'Nel mondo dell''informatica non si finisce mai di imparare, e seppur il persorso scolastico mi aveva dato una buona base, la curiosità di imparare le sfaccettature dietro un mondo così stratificato era tanta, e per questo ho deciso di proseguire gli Studi.' WHERE `id` = 'unibo-degree';
UPDATE `experiences` SET `narrative` = 'Finito il primo anno, sentivo che l''approccio universitario era troppo teorico e in un settore così pratico ero in cerca di una sfida che mi permettesse di fare un salto di qualità come sviluppatore. L’opportunità è arrivata con MyVet, un''idea appena nata che, come vice di un senior, ho contribuito a trasformare in un prodotto concreto. Essere Socio di una startup che ho fondato, ha profondamente cambiato il mio approccio alla programmazione e alla gestione dei progetti, portandomi a sviluppare competenze più avanzate in software architecture, project management e problem solving.' WHERE `id` = 'myvet-developer';
UPDATE `experiences` SET `narrative` = 'Il team cresceva, ma le richieste di funzionalità per i nostri prodotti erano tante. Date le skill personali dimostrate, mi è stata data l''opportunità di gestire in autonomia lo sviluppo di nuovi software e funzionalità critiche, avendo avuto spesso la possibilità di guidare un piccolo team' WHERE `id` = 'myvet-engineer';
UPDATE `experiences` SET `narrative` = 'Anche le belle cose hanno una fine e a seguito di una riorganizzazione interna di MyVet, ho pensato che per me era meglio scoprire altre realtà, per capire come altre aziende più stagionate gestiscono i propri flussi. In Egaf si predilige l''individualità e qui ho potuto in autonomia sviluppare servizi attorno al codice della strada e servizi legati ai dataset normativi.' WHERE `id` = 'egaf-engineer';
